import React, { useRef, useState, useCallback, useEffect } from 'react';

/**
 * CameraCapture - A reusable camera capture component using getUserMedia.
 * Enforces camera-only uploads on desktop where capture="environment" is ignored.
 *
 * Props:
 *   onCapture(files: File[]) - called when user confirms captured photos
 *   maxPhotos?: number - max photos allowed (default 5)
 *   label?: string - button label (default "Take Photos")
 *   disabled?: boolean
 *   multiple?: boolean - allow multiple captures (default true)
 */
function CameraCapture({ onCapture, maxPhotos = 5, label = 'Take Photos', disabled = false, multiple = true }) {
  const videoRef = useRef(null);
  const canvasRef = useRef(null);
  const streamRef = useRef(null);

  const [isOpen, setIsOpen] = useState(false);
  const [captured, setCaptured] = useState([]); // array of { preview: dataURL, file: File }
  const [error, setError] = useState(null);
  const [facingMode, setFacingMode] = useState('environment');

  const stopStream = useCallback(() => {
    if (streamRef.current) {
      streamRef.current.getTracks().forEach(track => track.stop());
      streamRef.current = null;
    }
    if (videoRef.current) {
      videoRef.current.srcObject = null;
    }
  }, []);

  useEffect(() => {
    return () => stopStream();
  }, [stopStream]);

  const startCamera = useCallback(async () => {
    setError(null);
    setCaptured([]);
    try {
      const constraints = {
        video: {
          facingMode,
          width: { ideal: 1920 },
          height: { ideal: 1080 }
        },
        audio: false
      };
      const stream = await navigator.mediaDevices.getUserMedia(constraints);
      streamRef.current = stream;
      if (videoRef.current) {
        videoRef.current.srcObject = stream;
        await videoRef.current.play();
      }
      setIsOpen(true);
    } catch (err) {
      console.error('Camera error:', err);
      setError(err.name === 'NotAllowedError'
        ? 'Camera permission denied. Please allow camera access in your browser settings.'
        : 'Could not access camera. Ensure your device has a camera and it is not being used by another app.'
      );
      setIsOpen(true);
    }
  }, [facingMode]);

  const takePhoto = useCallback(() => {
    const video = videoRef.current;
    const canvas = canvasRef.current;
    if (!video || !canvas || video.readyState !== 4) return;

    let width = video.videoWidth || 1280;
    let height = video.videoHeight || 720;
    // Cap resolution to keep file sizes mobile-friendly (max 1920 on longest side)
    const MAX_CAPTURE = 1920;
    if (width > MAX_CAPTURE || height > MAX_CAPTURE) {
      const ratio = Math.min(MAX_CAPTURE / width, MAX_CAPTURE / height);
      width = Math.round(width * ratio);
      height = Math.round(height * ratio);
    }
    canvas.width = width;
    canvas.height = height;

    const ctx = canvas.getContext('2d');
    ctx.drawImage(video, 0, 0, width, height);

    const dataURL = canvas.toDataURL('image/jpeg', 0.92);

    // Convert dataURL to File
    const byteString = atob(dataURL.split(',')[1]);
    const mimeString = dataURL.split(',')[0].split(':')[1].split(';')[0];
    const ab = new ArrayBuffer(byteString.length);
    const ia = new Uint8Array(ab);
    for (let i = 0; i < byteString.length; i++) {
      ia[i] = byteString.charCodeAt(i);
    }
    const blob = new Blob([ab], { type: mimeString });
    const file = new File([blob], `camera-photo-${Date.now()}.jpg`, { type: 'image/jpeg', lastModified: Date.now() });

    setCaptured(prev => {
      if (prev.length >= maxPhotos) return prev;
      return [...prev, { preview: dataURL, file }];
    });
  }, [maxPhotos]);

  const removePhoto = useCallback((idx) => {
    setCaptured(prev => prev.filter((_, i) => i !== idx));
  }, []);

  const handleDone = useCallback(() => {
    if (captured.length === 0) return;
    onCapture(captured.map(c => c.file));
    stopStream();
    setIsOpen(false);
    setCaptured([]);
  }, [captured, onCapture, stopStream]);

  const handleCancel = useCallback(() => {
    stopStream();
    setIsOpen(false);
    setCaptured([]);
    setError(null);
  }, [stopStream]);

  const toggleCamera = useCallback(() => {
    setFacingMode(prev => prev === 'environment' ? 'user' : 'environment');
    stopStream();
    setTimeout(() => startCamera(), 200);
  }, [stopStream, startCamera]);

  const canAddMore = captured.length < maxPhotos;
  const isAtLimit = captured.length >= maxPhotos;

  return (
    <>
      {/* Trigger button */}
      {!isOpen && (
        <button
          onClick={startCamera}
          disabled={disabled || isAtLimit}
          style={{
            display: 'block', width: '100%', border: '2px dashed #cbd5e1', borderRadius: 16,
            padding: 'clamp(10px, 3vw, 14px)', textAlign: 'center',
            cursor: disabled || isAtLimit ? 'not-allowed' : 'pointer',
            opacity: disabled || isAtLimit ? 0.5 : 1, transition: 'all 0.2s', background: '#f8fafc'
          }}
        >
          <div style={{ fontSize: 24, marginBottom: 4 }}>📷</div>
          <span style={{ fontSize: 12, color: '#64748b', fontWeight: 600 }}>
            {label} ({captured.length}/{maxPhotos})
          </span>
        </button>
      )}

      {/* Camera overlay modal */}
      {isOpen && (
        <div style={{
          position: 'fixed', top: 0, left: 0, right: 0, bottom: 0,
          background: 'rgba(0,0,0,0.85)', zIndex: 10050,
          display: 'flex', alignItems: 'center', justifyContent: 'center',
          padding: 16
        }}>
          <div style={{
            background: '#0f172a', borderRadius: 24, maxWidth: 520, width: '100%',
            height: 'min(90dvh, 720px)', maxHeight: '90dvh', overflow: 'auto', display: 'flex', flexDirection: 'column'
          }}>
            {/* Header */}
            <div style={{ display: 'flex', alignItems: 'center', justifyContent: 'space-between', padding: '16px 20px', borderBottom: '1px solid #1e293b' }}>
              <h3 style={{ margin: 0, color: 'white', fontSize: 16, fontWeight: 700 }}>📷 Camera</h3>
              <button onClick={handleCancel} style={{ background: 'none', border: 'none', color: '#94a3b8', fontSize: 20, cursor: 'pointer' }}>✕</button>
            </div>

            {/* Error state */}
            {error && (
              <div style={{ padding: 20, textAlign: 'center' }}>
                <div style={{ fontSize: 40, marginBottom: 12 }}>⚠️</div>
                <p style={{ color: '#f87171', fontSize: 14, fontWeight: 600, marginBottom: 16 }}>{error}</p>
                <button onClick={startCamera} style={{
                  padding: '10px 20px', borderRadius: 12, border: 'none', fontSize: 13, fontWeight: 700,
                  background: '#3b82f6', color: 'white', cursor: 'pointer'
                }}>Retry Camera</button>
              </div>
            )}

            {/* Video preview */}
            {!error && (
              <>
                <div style={{ position: 'relative', background: '#020617', aspectRatio: '4/3', overflow: 'hidden' }}>
                  <video
                    ref={videoRef}
                    autoPlay
                    playsInline
                    muted
                    style={{ width: '100%', height: '100%', objectFit: 'cover', transform: facingMode === 'user' ? 'scaleX(-1)' : 'none' }}
                  />
                  {/* Capture overlay hint */}
                  <div style={{
                    position: 'absolute', top: 8, left: '50%', transform: 'translateX(-50%)',
                    background: 'rgba(0,0,0,0.6)', color: 'white', fontSize: 11, fontWeight: 600,
                    padding: '4px 12px', borderRadius: 20
                  }}>
                    {captured.length}/{maxPhotos} captured
                  </div>
                </div>

                {/* Controls */}
                <div style={{ padding: 16, display: 'flex', gap: 12, justifyContent: 'center', alignItems: 'center', position: 'sticky', bottom: 0, background: '#0f172a', borderTop: '1px solid #1e293b', zIndex: 2 }}>
                  <button onClick={toggleCamera} style={{
                    width: 48, height: 48, borderRadius: '50%', border: '2px solid #475569',
                    background: '#1e293b', color: 'white', fontSize: 20, cursor: 'pointer',
                    display: 'flex', alignItems: 'center', justifyContent: 'center'
                  }} title="Switch camera">🔄</button>

                  <button
                    onClick={takePhoto}
                    disabled={!canAddMore}
                    style={{
                      width: 64, height: 64, borderRadius: '50%',
                      border: '4px solid white', background: canAddMore ? '#ef4444' : '#475569',
                      cursor: canAddMore ? 'pointer' : 'not-allowed',
                      flexShrink: 0
                    }}
                  />

                  <button onClick={handleDone} disabled={captured.length === 0} style={{
                    width: 48, height: 48, borderRadius: '50%', border: 'none',
                    background: captured.length > 0 ? '#22c55e' : '#475569', color: 'white',
                    fontSize: 18, cursor: captured.length > 0 ? 'pointer' : 'not-allowed',
                    display: 'flex', alignItems: 'center', justifyContent: 'center'
                  }} title="Done">✓</button>
                </div>
              </>
            )}

            {/* Captured thumbnails */}
            {captured.length > 0 && (
              <div style={{ padding: '0 16px 16px', display: 'flex', gap: 8, flexWrap: 'wrap', justifyContent: 'center' }}>
                {captured.map((c, idx) => (
                  <div key={idx} style={{ position: 'relative', width: 64, height: 64, borderRadius: 12, overflow: 'hidden', border: '2px solid #334155' }}>
                    <img src={c.preview} alt="" style={{ width: '100%', height: '100%', objectFit: 'cover' }} />
                    <button onClick={() => removePhoto(idx)} style={{
                      position: 'absolute', top: -2, right: -2, width: 20, height: 20,
                      background: '#ef4444', color: 'white', border: '2px solid #0f172a',
                      borderRadius: '50%', fontSize: 10, cursor: 'pointer', display: 'flex',
                      alignItems: 'center', justifyContent: 'center', padding: 0
                    }}>✕</button>
                  </div>
                ))}
              </div>
            )}
          </div>
        </div>
      )}

      {/* Hidden canvas for capture */}
      <canvas ref={canvasRef} style={{ display: 'none' }} />
    </>
  );
}

export default CameraCapture;
